// Destinatários do agente metas:
//   - diretor / supervisor / gerente
//   - com 'metas' no array `agentes` (Firestore users)
//   - com whatsapp válido
// Preserva o campo `loja` (string "todas" ou array) — vai ser usado depois.
return items
  .map(it => ({
    json: {
      email_login: (it.json.id || it.json.email_login || '').toLowerCase(),
      nome:        it.json.nome,
      funcao:      it.json.funcao,
      agentes:     it.json.agentes,
      whatsapp:    String(it.json.whatsapp || '').trim(),
      loja:        it.json.loja,   // preservado p/ o nó "Resolver visibilidade"
    }
  }))
  .filter(it => {
    const d = it.json;
    return ['diretor', 'supervisor', 'gerente'].includes(d.funcao)
      && Array.isArray(d.agentes) && d.agentes.includes('metas')
      && d.whatsapp && d.whatsapp !== '0' && d.whatsapp.length > 5
      && d.email_login;
  });

// Cruza cada usuário (do nó 'Filtrar destinatários') com o resumo
// completo do Supabase (do nó 'Supabase: resumo (todas filiais)').
//
// Regra de visibilidade (definida 2026-05-18): a fonte de verdade é
// users/{email}.loja no Firestore.
//   - "todas" (string ou item de array, case-insensitive) → wildcard (vê tudo)
//   - array de strings ('305', '305 - ELETRO ...') → filtra por essas
//   - vazio/ausente → não vê nada
//
// Sai: 1 item por usuário, com o resumo já filtrado pelas lojas dele.
const usuarios = $('Filtrar destinatários').all().map(it => it.json);
const resumoTodo = $('Supabase: resumo (todas filiais)').all().map(it => it.json);

const SENTINEL = 'todas';
function extrai(raw) {
  if (raw == null) return null;
  const s = String(raw).trim();
  if (!s) return null;
  const m = s.match(/^(\d+)/);
  return m ? m[1] : s.toLowerCase();
}

function resolveLojas(lojaRaw) {
  if (typeof lojaRaw === 'string' && lojaRaw.trim().toLowerCase() === SENTINEL) {
    return { wildcard: true, filiais: [] };
  }
  const arr = Array.isArray(lojaRaw) ? lojaRaw : (lojaRaw == null || lojaRaw === '' ? [] : [lojaRaw]);
  if (arr.some(x => String(x).trim().toLowerCase() === SENTINEL)) {
    return { wildcard: true, filiais: [] };
  }
  const filiais = arr.map(extrai).filter(Boolean).filter((v, i, a) => a.indexOf(v) === i);
  return { wildcard: false, filiais };
}

return usuarios.map(u => {
  const { wildcard, filiais } = resolveLojas(u.loja);
  const resumo = wildcard
    ? resumoTodo
    : resumoTodo.filter(r => filiais.includes(String(r.filial_cod)));
  return {
    json: {
      email_login: u.email_login,
      nome:        u.nome,
      whatsapp:    u.whatsapp,
      funcao:      u.funcao,
      wildcard,
      filiais,
      resumo,
    }
  };
});

// Monta a mensagem do WhatsApp.
//   - wildcard=true  → TOP 3 filiais piores por % atingido (diretor/supervisor)
//   - wildcard=false → sua(s) filial(is) em risco (gerente)
const u = $input.first().json;
const nome = u.nome;
const wildcard = !!u.wildcard;

function money(v) {
  if (v == null) return '—';
  return Number(v).toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 });
}
function pct(v) {
  if (v == null) return '—';
  return Number(v).toFixed(0) + '%';
}
function recuperar(r) {
  if (r.venda_para_recuperar_loja == null) return '';
  const dias = r.dias_restantes_loja != null ? ` em ${r.dias_restantes_loja}d` : '';
  return ` • precisa ${money(r.venda_para_recuperar_loja)}/dia${dias}`;
}

const comRisco = (u.resumo || []).filter(r =>
  r.loja_em_risco || r.setores_em_risco > 0 || r.departamentos_em_risco > 0 || r.secoes_em_risco > 0
);

let message;
if (wildcard) {
  const top3 = [...comRisco]
    .filter(r => r.percent_loja != null)
    .sort((a, b) => Number(a.percent_loja) - Number(b.percent_loja))
    .slice(0, 3);

  const titulo = top3.length === 1 ? '1 filial em risco hoje:'
               : top3.length === 2 ? '2 filiais em risco hoje:'
               : 'TOP 3 filiais mais distantes da meta hoje:';

  const linhas = top3.map((r, i) => {
    const pos = ['1º','2º','3º'][i] || `${i+1}º`;
    const bits = [`${pct(r.percent_loja)} atingido`, `tend. ${money(r.tendencia_loja)} / meta ${money(r.meta_loja_venda)}`];
    const sub = [];
    if (r.setores_em_risco > 0)       sub.push(`${r.setores_em_risco} setor(es)`);
    if (r.departamentos_em_risco > 0) sub.push(`${r.departamentos_em_risco} dept(s)`);
    if (r.secoes_em_risco > 0)        sub.push(`${r.secoes_em_risco} seç(ões)`);
    if (sub.length) bits.push(sub.join(' • ') + ' em risco');
    return `${pos} *${r.filial_cod}* — ${bits.join(' • ')}${recuperar(r)}`;
  }).join('\n');

  message = `Olá, *${nome}*!\n\nAcompanhamento de *metas* — ${titulo}\n\n${linhas}\n\nAcesse: ${$env.APP_URL_METAS || 'http://margem.interno/agente/metas'}`;
} else {
  const linhas = comRisco.map(r => {
    const bits = [];
    bits.push(`Venda atual: ${money(r.venda_loja)}`);
    bits.push(`Meta: ${money(r.meta_loja_venda)}`);
    bits.push(`Tendência: ${money(r.tendencia_loja)} (${pct(r.percent_loja)} atingido)`);
    if (r.venda_para_recuperar_loja != null) {
      const dias = r.dias_restantes_loja != null ? ` (${r.dias_restantes_loja}d restantes)` : '';
      bits.push(`Precisa vender ${money(r.venda_para_recuperar_loja)}/dia${dias} para recuperar`);
    }
    const sub = [];
    if (r.setores_em_risco > 0)       sub.push(`${r.setores_em_risco} setor(es)`);
    if (r.departamentos_em_risco > 0) sub.push(`${r.departamentos_em_risco} dept(s)`);
    if (r.secoes_em_risco > 0)        sub.push(`${r.secoes_em_risco} seç(ões)`);
    if (sub.length) bits.push(`⚠ ${sub.join(' • ')} em risco`);
    return `*${r.filial_desc || r.filial_cod}*\n   ` + bits.join('\n   ');
  }).join('\n\n');

  message = `Olá, *${nome}*!\n\nAcompanhamento de *metas* — sua filial:\n\n${linhas}\n\nAcesse: ${$env.APP_URL_METAS || 'http://margem.interno/agente/metas'}`;
}

return [{
  json: {
    phone: u.whatsapp,
    message,
    email_login: u.email_login,
  }
}];
